const APP_NAME = 'cpa-cron-web';
const APP_SHORT_NAME = 'cpa-cron';
const APP_DESCRIPTION = 'CPA 账号管理与维护 Web 控制台';
const APP_THEME_COLOR = '#6c5ce7';
const APP_BACKGROUND_COLOR = '#0f1117';
const PWA_CACHE_VERSION = '2026-04-18-5';

const APP_ICON_180_PNG_BASE64 = '';
const APP_ICON_192_PNG_BASE64 = '';
const APP_ICON_512_PNG_BASE64 = '';

function decodeBase64(value: string): Uint8Array {
  const binary = atob(value);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i += 1) {
    bytes[i] = binary.charCodeAt(i);
  }
  return bytes;
}

export function buildPwaManifest(): string {
  return JSON.stringify({
    id: '/',
    name: APP_NAME,
    short_name: APP_SHORT_NAME,
    description: APP_DESCRIPTION,
    start_url: '/',
    scope: '/',
    display: 'standalone',
    orientation: 'portrait',
    background_color: APP_BACKGROUND_COLOR,
    theme_color: APP_THEME_COLOR,
    categories: ['productivity', 'utilities'],
    lang: 'zh-CN',
    icons: [
      {
        src: '/assets/app-icon-192.png',
        sizes: '192x192',
        type: 'image/png',
        purpose: 'any',
      },
      {
        src: '/assets/app-icon-512.png',
        sizes: '512x512',
        type: 'image/png',
        purpose: 'any maskable',
      },
      {
        src: '/assets/app-icon.svg',
        sizes: 'any',
        type: 'image/svg+xml',
        purpose: 'any',
      },
    ],
    shortcuts: [
      { name: '仪表盘', short_name: '仪表盘', url: '/' },
      { name: '账号管理', short_name: '账号', url: '/accounts' },
      { name: '系统配置', short_name: '配置', url: '/settings' },
    ],
  }, null, 2);
}

export function buildServiceWorker(): string {
  return String.raw`const CACHE_NAME = 'cpa-cron-web-shell-2026-04-18-5';
const APP_SHELL = [
  '/',
  '/login',
  '/manifest.webmanifest',
  '/favicon.ico',
  '/apple-touch-icon.png',
  '/assets/app-icon.svg',
  '/assets/app-icon-192.png',
  '/assets/app-icon-512.png'
];

self.addEventListener('install', (event) => {
  event.waitUntil((async () => {
    const cache = await caches.open(CACHE_NAME);
    await cache.addAll(APP_SHELL);
    await self.skipWaiting();
  })());
});

self.addEventListener('activate', (event) => {
  event.waitUntil((async () => {
    const keys = await caches.keys();
    await Promise.all(keys.filter((key) => key !== CACHE_NAME).map((key) => caches.delete(key)));
    await self.clients.claim();
  })());
});

async function networkFirst(request) {
  const cache = await caches.open(CACHE_NAME);
  try {
    const response = await fetch(request);
    if (response && response.ok) {
      cache.put(request, response.clone()).catch(() => {});
    }
    return response;
  } catch (error) {
    const cached = await cache.match(request);
    if (cached) return cached;
    return (await cache.match('/')) || (await cache.match('/login')) || Response.error();
  }
}

async function staleWhileRevalidate(request) {
  const cache = await caches.open(CACHE_NAME);
  const cached = await cache.match(request);
  const networkPromise = fetch(request).then((response) => {
    if (response && response.ok) {
      cache.put(request, response.clone()).catch(() => {});
    }
    return response;
  }).catch(() => null);

  if (cached) {
    networkPromise.catch(() => null);
    return cached;
  }

  const networkResponse = await networkPromise;
  return networkResponse || Response.error();
}

self.addEventListener('fetch', (event) => {
  const request = event.request;
  if (request.method !== 'GET') return;

  const url = new URL(request.url);
  if (url.origin !== self.location.origin) return;
  if (url.pathname.startsWith('/api/')) return;

  if (request.mode === 'navigate') {
    event.respondWith(networkFirst(request));
    return;
  }

  if (
    url.pathname === '/manifest.webmanifest' ||
    url.pathname === '/sw.js' ||
    url.pathname === '/favicon.ico' ||
    url.pathname === '/apple-touch-icon.png' ||
    url.pathname.startsWith('/assets/')
  ) {
    event.respondWith(staleWhileRevalidate(request));
  }
});`;
}

export function getPngIconBody(size: 180 | 192 | 512): Uint8Array {
  switch (size) {
    case 180:
      return decodeBase64(APP_ICON_180_PNG_BASE64);
    case 192:
      return decodeBase64(APP_ICON_192_PNG_BASE64);
    case 512:
      return decodeBase64(APP_ICON_512_PNG_BASE64);
    default:
      return decodeBase64(APP_ICON_192_PNG_BASE64);
  }
}

export const PWA_METADATA = {
  appName: APP_NAME,
  shortName: APP_SHORT_NAME,
  description: APP_DESCRIPTION,
  themeColor: APP_THEME_COLOR,
  backgroundColor: APP_BACKGROUND_COLOR,
  cacheVersion: PWA_CACHE_VERSION,
  manifestHref: '/manifest.webmanifest',
  appleTouchIconHref: '/apple-touch-icon.png',
  serviceWorkerHref: '/sw.js',
} as const;
